/// <summary>
/// Sales line impoort
/// </summary>
public class ETG_Acu_SalesLineImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_SalesLineImport  salesLineimport;

    salesLineimport = ETG_Acu_SalesLineImport::construct();

    if (salesLineimport.prompt())
    {
        salesLineimport.runOperation();
    }
}

public static ETG_Acu_SalesLineImport construct()
{
    return new ETG_Acu_SalesLineImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    SalesOrderLineV2Entity      salesLine;
    SalesOrderHeaderV3Entity    salesTable;

    salesLine.AllowedOverdeliveryPercentage         = conpeek(_con, 1);
    salesLine.AllowedUnderdeliveryPercentage        = conpeek(_con, 2);
    salesLine.ConfirmedReceiptDate                  = str2Date(conpeek(_con, 3), 123);
    salesLine.ConfirmedShippingDate                 = str2Date(conpeek(_con, 4), 123);
    salesLine.CurrencyCode                          = conpeek(_con, 5);
    //salesLine.DefaultLedgerDimensionDisplayValue    = conpeek(_con, 6);
    /*salesLine.DeliveryAddressCountryRegionId        = conpeek(_con, 7);
    salesLine.DeliveryAddressDescription            = conpeek(_con, 8);
    salesLine.DeliveryAddressName                   = conpeek(_con, 9);
    salesLine.DeliveryAddressStreet                 = conpeek(_con, 10);*/
    salesLine.DeliveryModeCode                      = conpeek(_con, 11);
    salesLine.ItemNumber                            = conpeek(_con, 12);
    salesLine.LineAmount                            = conpeek(_con, 13);
    salesLine.LineNumber                            = conpeek(_con, 14);
    salesLine.LineDescription                       = conpeek(_con, 15);
    salesLine.OrderedSalesQuantity                  = conpeek(_con, 16);
    salesLine.ProductColorId                        = conpeek(_con, 17);
    salesLine.ProductConfigurationId                = conpeek(_con, 18);
    salesLine.ProductSizeId                         = conpeek(_con, 19);
    salesLine.ProductStyleId                        = conpeek(_con, 20);
    salesLine.RequestedReceiptDate                  = str2Date(conpeek(_con, 21), 123);
    salesLine.RequestedShippingDate                 = str2Date(conpeek(_con, 22), 123);
    salesLine.SalesOrderNumber                      = conpeek(_con, 24);
    salesLine.SalesPrice                            = conpeek(_con, 25);
    salesLine.SalesPriceQuantity                    = conpeek(_con, 26);
    salesLine.SalesUnitSymbol                       = conpeek(_con, 27);
    salesLine.ShippingSiteId                        = conpeek(_con, 28);
    salesLine.ShippingWarehouseId                   = conpeek(_con, 29);
    salesLine.ShippingWarehouseLocationId           = conpeek(_con, 30);

    select firstonly salesTable
        where salesTable.SalesOrderNumber   == salesLine.SalesOrderNumber;

    salesLine.DeliveryAddressLocationId             = salesTable.DeliveryAddressLocationId;

    // BusinessUnit (31)	Contract (32)	Department (33)	Intercompany (34)	Plant_Warehouse_Office (35)	Product_Service (36)	Trader_Employee (37)
    // |Plant_Warehouse_Office|Department|Trader_Employee|Product_Service|BusinessUnit|Intercompany|Contract

    salesLine.DefaultLedgerDimensionDisplayValue  = conPeek(_con, 35) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 33) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 37) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 36) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 31) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 34) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 32);
    salesLine.insert();
}

/// <summary>
///Import inventory site
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpOpenSalesLine";

    return ret;
}
